import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import SliderInput from "@/components/SliderInput";
import FAQItem from "@/components/FAQItem";


const FAQS = [
  { q: "What is the elapsed time (ET) method for calculating horsepower?", a: "The ET method uses quarter-mile elapsed time and vehicle weight: HP = Weight / (ET/5.825)- This formula was developed for drag racing where elapsed time is easily measured. It estimates flywheel horsepower from on-track performance. Weight should include driver and any fluids." },
  { q: "What is BSFC and how does it affect horsepower calculations?", a: "BSFC (Brake Specific Fuel Consumption) measures fuel efficiency in pounds of fuel per horsepower-hour. It's used to calculate horsepower from measured fuel flow: HP = Fuel Flow (lb/hr) / BSFC. Naturally aspirated gasoline engines typically have BSFC of 0.45-0.55. Forced induction engines may be 0.55-0.65." },
  { q: "What is a dynamometer (dyno) test?", a: "A dynamometer measures actual power output. A chassis dyno measures wheel horsepower (what actually drives you). An engine dyno measures brake horsepower at the crankshaft. Drivetrain losses between engine and wheels are typically 15-20% for rear-wheel drive, 10-15% for front-wheel drive vehicles." },
  { q: "How do I estimate horsepower from a 0-60 time?", a: "Estimated HP - (Vehicle Weight  x  0-60 accel factor) / time. This is a rough approximation only. Actual HP depends heavily on traction, gearing, aerodynamics, tire slip, and mechanical losses. The quarter-mile ET and trap speed formulas are much more accurate than 0-60 times." },
  { q: "What is the difference between horsepower and torque?", a: "Torque measures rotational force (lb-ft). Horsepower is derived from torque: HP = Torque (lb-ft)  x  RPM / 5,252. Torque tells you how hard an engine pulls; horsepower tells you how much work it can do over time. They always intersect at 5,252 RPM on a dyno chart." },
  { q: "How accurate are quarter-mile-based HP estimates?", a: "Quarter-mile HP estimates from ET and trap speed are reasonably accurate for stock or mildly modified cars on good tracks, typically within 5-10% of dyno results. Extreme modifications, unusual weight distributions, or poor traction can throw off the estimate significantly." },
  { q: "What quarter-mile times correspond to common horsepower levels?", a: "A 3,500-lb car running: 15.5 sec - 150 HP, 14.5 sec - 200 HP, 13.5 sec - 260 HP, 12.5 sec - 340 HP, 11.5 sec - 450 HP, 10.5 sec - 620 HP. These are rough estimates for typical street cars with all-season tires." },
  { q: "How does altitude affect engine horsepower?", a: "Naturally aspirated engines lose approximately 3% horsepower for every 1,000 feet of altitude, as thinner air means less oxygen for combustion. At 5,000 feet (Denver), a 300 HP engine makes approximately 255 HP. Turbocharged and supercharged engines lose much less power at altitude, making them advantageous in high-elevation locations." },
];

const REFERENCE = [
  ["Commuter car", "3,200 lbs", "120-150 HP", "16.5-18 sec"],
  ["Family sedan", "3,700 lbs", "180-220 HP", "14.5-15.5 sec"],
  ["Sport sedan", "3,800 lbs", "280-350 HP", "12.5-13.5 sec"],
  ["Sports car", "3,200 lbs", "350-450 HP", "11.5-12.5 sec"],
  ["Muscle car", "4,000 lbs", "450-600 HP", "11.0-12.0 sec"],
  ["Supercar", "3,400 lbs", "600-800 HP", "9.5-11.0 sec"],
  ["Pro Stock drag car", "2,350 lbs", "1,400+ HP", "< 6.5 sec"],
];

export default function EngineHorsepowerCalculator() {
  const [weight, setWeight] = useState(3500);
  const [etSecs, setEtSecs] = useState(13.5);
  const [trapSpeed, setTrapSpeed] = useState(105);
  const [method, setMethod] = useState<"et" | "speed">("et");

  const hpFromET = weight / Math.pow(etSecs / 5.825, 3);
  const hpFromSpeed = weight * Math.pow(trapSpeed / 234, 3);
  const hp = method === "et" ? hpFromET : hpFromSpeed;
  const kw = hp * 0.7457;
  const torqueAt5252 = hp;

  return (
    <>
      <SEOHead
        title="Free Engine Horsepower Calculator Online - Estimate HP From Quarter Mile Instantly | CalcHive"
        description="Free online engine horsepower calculator. Estimate engine HP from quarter-mile elapsed time or trap speed using the drag racing formula instantly. 100% free for car enthusiasts, no signup required."
        canonical="/engine-horsepower-calculator"
        keywords="free engine horsepower calculator, quarter mile horsepower calculator free, drag racing HP calculator free online, estimate engine HP free, trap speed horsepower calculator free"
        category="Automotive Calculators"
        faqs={FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-rose-600 dark:text-rose-400 bg-rose-50 dark:bg-rose-950/50 px-3 py-1 rounded-full mb-4 inline-block">Transportation</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Engine Horsepower Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free engine horsepower calculator to estimate engine HP free from quarter-mile elapsed time or trap speed. This quarter mile horsepower calculator free also works as a drag racing HP calculator free online and trap speed horsepower calculator free.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <div className="flex gap-2 mb-6">
          {[["et", "From Elapsed Time (ET)"], ["speed", "From Trap Speed"]].map(([v, l]) => (
            <button key={v} onClick={() => setMethod(v as "et" | "speed")} className={`flex-1 py-2 rounded-xl text-sm font-semibold border transition-all ${method === v ? "bg-rose-600 text-white border-rose-600" : "bg-card text-muted-foreground border-border hover:border-rose-400"}`}>{l}</button>
          ))}
        </div>
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="space-y-6 mb-8">
            <SliderInput id="weight" label="Vehicle Weight (lbs) - include driver" value={weight} min={500} max={10000} step={50} onChange={setWeight} format={v => `${v.toLocaleString()} lbs`} testId="input-weight" />
            {method === "et" ? (
              <SliderInput id="et" label="Quarter-Mile ET (seconds)" value={etSecs} min={8} max={25} step={0.01} onChange={setEtSecs} format={v => `${v.toFixed(2)} sec`} testId="input-et" />
            ) : (
              <SliderInput id="speed" label="Quarter-Mile Trap Speed (mph)" value={trapSpeed} min={50} max={250} step={0.5} onChange={setTrapSpeed} format={v => `${v} mph`} testId="input-speed" />
            )}
          </div>
          <motion.div key={`${method}-${weight}-${etSecs}-${trapSpeed}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-rose-500 to-rose-700 rounded-2xl p-6 mb-4 text-center shadow-lg">
              <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Estimated Horsepower</p>
              <p className="text-6xl font-black text-white tracking-tight" data-testid="result-hp">{hp.toFixed(0)} HP</p>
              <p className="text-white/70 text-sm mt-1">{kw.toFixed(0)} kW - torque - {torqueAt5252.toFixed(0)} lb-ft at 5,252 RPM</p>
            </div>
            <div className="grid grid-cols-2 gap-3">
              {[
                { label: "Kilowatts (kW)", value: kw.toFixed(1) },
                { label: "Formula Used", value: method === "et" ? "W / (ET/5.825)^3" : "W x (Speed/234)^3" },
              ].map(({ label, value }) => (
                <div key={label} className="bg-accent/60 border border-border rounded-xl p-4 text-center">
                  <p className="text-xs text-muted-foreground font-medium mb-1">{label}</p>
                  <p className="text-base font-extrabold text-foreground font-mono">{value}</p>
                </div>
              ))}
            </div>
          </motion.div>
        </section>
        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Estimate Engine HP From Quarter Mile Time for Free</h2>
          <p className="text-muted-foreground leading-relaxed">Both formulas were developed empirically from real-world drag racing data. They give consistent estimates for stock and mildly modified street cars but may deviate for highly modified or unusually aerodynamic vehicles. The trap speed method is generally considered slightly more accurate than the ET method.</p>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground space-y-3">
            <div>
              <p className="text-xs text-muted-foreground uppercase tracking-widest mb-1">ET Method (quarter-mile elapsed time)</p>
              <p>HP = Vehicle Weight (lbs) / (ET / 5.825)^3</p>
            </div>
            <div>
              <p className="text-xs text-muted-foreground uppercase tracking-widest mb-1">Trap Speed Method (quarter-mile exit speed)</p>
              <p>HP = Vehicle Weight (lbs) x (Trap Speed / 234)^3</p>
            </div>
            <div>
              <p className="text-xs text-muted-foreground uppercase tracking-widest mb-1">Horsepower - Torque Relationship</p>
              <p>HP = Torque (lb-ft)  x  RPM  x  5,252</p>
            </div>
          </div>

          <h2 className="text-2xl font-bold text-foreground">How the Drag Racing Horsepower Formula Works</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Vehicle Type", "Typical Weight", "Estimated HP", "Typical 1/4 Mile ET"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {REFERENCE.map(([type, wt, hp_, et_]) => (
                  <tr key={type} className="hover:bg-muted/30">
                    <td className="py-2.5 px-4 font-semibold text-foreground">{type}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{wt}</td>
                    <td className="py-2.5 px-4 text-rose-600 dark:text-rose-400 font-bold">{hp_}</td>
                    <td className="py-2.5 px-4 text-muted-foreground font-mono">{et_}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          <h2 className="text-2xl font-bold text-foreground">Free Quarter Mile HP Estimator for Car Enthusiasts</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["HP (SAE)", "kW (metric)", "PS (DIN/metric HP)", "ft-lb/s"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {[100, 150, 200, 300, 400, 500, 700, 1000].map(h => (
                  <tr key={h} className={`hover:bg-muted/30 ${Math.abs(h - hp) < 30 ? "bg-rose-50 dark:bg-rose-950/20 font-semibold" : ""}`}>
                    <td className="py-2.5 px-4 font-bold text-rose-600 dark:text-rose-400">{h} HP</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{(h * 0.7457).toFixed(1)} kW</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{(h * 1.01387).toFixed(1)} PS</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{(h * 550).toLocaleString()} ft-lb/s</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </section>

        <section className="mb-8">
          <h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3>
          <div className="space-y-3">{FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/engine-horsepower-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


